css:
.loading-bar {
  position: relative;
  width: 110px;
  height: 110px;
  background: transparent;
  border: 3px solid #3c3c3c;
  border-radius: 50%;
  text-align: center;
  line-height: 111px;
  font-family: sans-serif;
  font-size: 15px;
  color: #fff000;
  letter-spacing: 3px;
  text-transform: uppercase;
  text-shadow: 0 0 20px #fff000;
  box-shadow: 0 0 20px rgba(0,0,0,.5);
}
.loading-bar::before {
  content: "";
  position: absolute;
  top: -3px;
  left: -3px;
  width: 100%;
  height: 100%;
  border: 3px solid transparent;
  border-top: 5px solid #fff000;
  border-right: 5px solid #fff000;
  border-radius: 50%;
  animation: solarDial 2s linear infinite;
}
.loading-bar span {
  position: absolute;
  top: calc(50% - 2px);
  left: 50%;
  width: 50%;
  height: 4px;
  background: transparent;
  transform-origin: left;
  animation: solarHand 2s linear infinite;
}
.loading-bar span::before {
  content: "";
  position: absolute;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: #fff000;
  top: -5px;
  right: -7px;
  box-shadow: 0 0 20px #fff000;
}
@keyframes solarDial { to { transform: rotate(360deg); } }
@keyframes solarHand { from { transform: rotate(45deg); } to { transform: rotate(405deg); } }
